code = """import json
import re

# Get file paths  
pkg_path = locals()['var_functions.query_db:8']
ver_path = locals()['var_functions.query_db:10']
proj_path = locals()['var_functions.query_db:12']

# Load data
pkg_data = json.load(open(pkg_path))
ver_data = json.load(open(ver_path))
proj_data = json.load(open(proj_path))

# Find latest NPM release per package
latest = {}
for p in pkg_data:
    if p.get('System') == 'NPM':
        try:
            vi = json.loads(p['VersionInfo'].strip())
            if vi.get('IsRelease'):
                name = p['Name']
                if name not in latest or vi['Ordinal'] > latest[name].get('ordinal', 0):
                    latest[name] = {'version': p['Version'], 'ordinal': vi['Ordinal']}
        except:
            continue

# Extract stars from project info
proj_stars = {}
for proj in proj_data:
    info = str(proj.get('Project_Information', ''))
    match = re.search(r'(\d{1,3}(?:,\d{3})*)\s+stars?', info, re.I)
    if match:
        stars = int(match.group(1).replace(',', ''))
        match2 = re.search(r'project\s+(\S+\/\S+?)[\s,]', info, re.I)
        if match2:
            proj_stars[match2.group(1)] = stars

# Map versions to projects
ver_map = {(v['System'], v['Name'], v['Version']): v for v in ver_data}

# Find packages with stars
results = []
for name, info in latest.items():
    key = ('NPM', name, info['version'])
    if key in ver_map:
        proj = ver_map[key]['ProjectName']
        if proj in proj_stars:
            results.append([name, info['version'], proj_stars[proj], proj])

# Sort and format top 5
top5 = sorted(results, key=lambda x: x[2], reverse=True)[:5]
output_lines = []
for r in top5:
    output_lines.append(r[0] + ' version ' + r[1] + ' - ' + str(r[2]) + ' GitHub stars')

result_str = '\n'.join(output_lines) if output_lines else 'No results'

print('__RESULT__:')
print(result_str)"""

